import { PopupDialog } from '@/components/PopupDialog'
import { Button } from '@/components/ui/button'
import { cn } from '@/lib/utils'
import Image from 'next/image'
import React from 'react'

const RootPage = () => {
    return (
        <div className='flex flex-col justify-center items-center h-screen'>
            <div className='w-full max-w-[333px] border-1 p-10 rounded-sm flex flex-col items-center bg-[#216c58]'>
                <Image
                    src='/app_logo.png'
                    width={80}
                    height={80}
                    priority={true}
                    alt="Picture of the author"
                    className="rounded-sm mb-8"
                />
                <PopupDialog />
                {/* <Button
                    className="cursor-pointer bg-[#f7f5dc] text-black-400 hover:bg-[#fcf10b]"
                >Proceed Transaction</Button> */}
            </div>
        </div>
    )
}

export default RootPage